## API Endpoints

```javascript
// Express.js routes

// Upload CSV
app.post('/api/upload', upload.single('file'), async (req, res) => {
  const profiles = parseCSV(req.file.buffer);
  const id = saveToDatabase(profiles);
  res.json({ id, count: profiles.length });
});

// Start enrichment
app.post('/api/enrich/:id', async (req, res) => {
  const { id } = req.params;
  // Start background job
  enrichmentQueue.add({ projectId: id });
  res.json({ status: 'started' });
});

// Get enrichment status
app.get('/api/enrich/:id/status', (req, res) => {
  const status = getEnrichmentStatus(req.params.id);
  res.json(status);
});

// Search profiles
app.post('/api/search', async (req, res) => {
  const { projectId, query } = req.body;
  const results = await searchProfiles(query, projectId);
  res.json(results);
});

// Export CSV
app.get('/api/export/:id', (req, res) => {
  const csv = generateCSV(req.params.id);
  res.setHeader('Content-Type', 'text/csv');
  res.setHeader('Content-Disposition', 'attachment; filename=enriched_profiles.csv');
  res.send(csv);
});
```

