{
  "name": "TechWalk Connect",
  "description": "An AI-powered networking intelligence tool that enriches event attendee data using Gemini AI and provides semantic search capabilities."
}

export interface Profile {
  id: string;
  name: string;
  title: string;
  company: string;
  linkedin_url?: string;
  email?: string;

  // Enriched data
  background?: string;
  what_they_do?: string;
  achievements?: string;
  skills?: string[];

  // Metadata
  enrichment_status: 'pending' | 'processing' | 'success' | 'fallback' | 'error';
  enrichment_source: 'none' | 'gemini_web' | 'title_inference';
  embedding?: number[];
  score?: number; // for search ranking
}

export interface EnrichmentProgress {
  current: number;
  total: number;
  percentage: string;
  currentName: string;
  logs: Array<{
    name: string;
    status: 'success' | 'error' | 'processing' | 'fallback';
    message: string;
  }>;
}

export interface EnrichmentResult {
  background: string;
  what_they_do: string;
  achievements: string;
  skills: string[];
  is_valid: boolean;
}

export interface FallbackResult {
  typical_responsibilities: string;
  typical_skills: string[];
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { EnrichmentResult, FallbackResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

/**
 * Uses Gemini with Google Search tool to find and extract profile info.
 */
export async function enrichWithGemini(
  name: string,
  title: string,
  company: string
): Promise<EnrichmentResult> {
  const prompt = `
    You are a professional profile analyzer. Your goal is to find information about this person online (LinkedIn, personal sites, company bios) and summarize it.

    **Person:** ${name}
    **Role:** ${title} at ${company}

    **Your Task:**
    Search for this specific person and return a JSON object with:
    1. "background": 2-3 sentence summary of professional background/career history.
    2. "what_they_do": 1-2 sentences on current responsibilities/projects.
    3. "achievements": Notable awards, publications, or recognition.
    4. "skills": Array of 5-15 technical and professional skills.
    5. "is_valid": boolean (true if you found clear info about THIS person, false if results were mostly ads or unrelated).

    Return ONLY valid JSON. If no info is found, return empty strings for text and empty array for skills.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            background: { type: Type.STRING },
            what_they_do: { type: Type.STRING },
            achievements: { type: Type.STRING },
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            is_valid: { type: Type.BOOLEAN }
          },
          required: ["background", "what_they_do", "achievements", "skills", "is_valid"]
        }
      },
    });

    return JSON.parse(response.text.trim()) as EnrichmentResult;
  } catch (error) {
    console.error(`Gemini Enrichment Error for ${name}:`, error);
    throw error;
  }
}

/**
 * Fallback to infer info from a job title if web search fails.
 */
export async function inferFromTitle(title: string, company: string): Promise<FallbackResult> {
  const prompt = `
    Given this job title and company, provide typical professional information:
    Title: ${title}
    Company: ${company}

    Return JSON with:
    {
      "typical_responsibilities": "1-2 sentences about what someone in this role typically does",
      "typical_skills": ["array", "of", "5-10", "typical", "skills"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            typical_responsibilities: { type: Type.STRING },
            typical_skills: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["typical_responsibilities", "typical_skills"]
        }
      }
    });

    return JSON.parse(response.text.trim()) as FallbackResult;
  } catch (error) {
    console.error(`Gemini Fallback Error:`, error);
    throw error;
  }
}

/**
 * Generates embeddings for a profile's text to enable semantic search.
 */
export async function getProfileEmbedding(text: string): Promise<number[]> {
  try {
    // Note: The GenAI SDK currently uses a specific model for embeddings.
    // We use a separate call if the SDK supports it or fallback to a text-generating model approach if not.
    // Using gemini-3-flash-preview for "fake" embeddings isn't ideal, but many environments provide
    // text-embedding-004. We will attempt a standard model call for embedding.
    const model = ai.getGenerativeModel({ model: "text-embedding-004" });
    const result = await model.embedContent(text);
    return result.embedding.values;
  } catch (error) {
    console.warn("Embedding failed, falling back to dummy or skipping semantic search features.");
    return new Array(768).fill(0); // Dummy fallback
  }
}

export function cosineSimilarity(a: number[], b: number[]): number {
  if (!a || !b || a.length !== b.length) return 0;
  let dotProduct = 0;
  let normA = 0;
  let normB = 0;
  for (let i = 0; i < a.length; i++) {
    dotProduct += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  const denominator = Math.sqrt(normA) * Math.sqrt(normB);
  return denominator === 0 ? 0 : dotProduct / denominator;
}

import { Profile } from "../types";

export function parseCSV(text: string): Partial<Profile>[] {
  const lines = text.split(/\r?\n/).filter(line => line.trim().length > 0);
  if (lines.length < 2) return [];

  const headers = lines[0].split(',').map(h => h.trim().toLowerCase());

  const nameIdx = headers.findIndex(h => h.includes('name'));
  const titleIdx = headers.findIndex(h => ['title', 'role', 'position'].some(k => h.includes(k)));
  const companyIdx = headers.findIndex(h => ['company', 'org', 'employer'].some(k => h.includes(k)));
  const linkedinIdx = headers.findIndex(h => ['linkedin', 'url', 'link'].some(k => h.includes(k)));
  const emailIdx = headers.findIndex(h => h.includes('email'));

  return lines.slice(1).map((line, i) => {
    const values = line.split(',').map(v => v.trim());
    return {
      id: `profile-${i}-${Date.now()}`,
      name: values[nameIdx] || 'Unknown',
      title: values[titleIdx] || 'N/A',
      company: values[companyIdx] || 'N/A',
      linkedin_url: linkedinIdx !== -1 ? values[linkedinIdx] : undefined,
      email: emailIdx !== -1 ? values[emailIdx] : undefined,
      enrichment_status: 'pending',
      enrichment_source: 'none'
    };
  });
}

export function exportToCSV(profiles: Profile[]): string {
  const headers = ['Name', 'Title', 'Company', 'LinkedIn', 'Background', 'Responsibilities', 'Achievements', 'Skills'];
  const rows = profiles.map(p => [
    `"${p.name}"`,
    `"${p.title}"`,
    `"${p.company}"`,
    `"${p.linkedin_url || ''}"`,
    `"${(p.background || '').replace(/"/g, '""')}"`,
    `"${(p.what_they_do || '').replace(/"/g, '""')}"`,
    `"${(p.achievements || '').replace(/"/g, '""')}"`,
    `"${(p.skills || []).join(', ')}"`
  ].join(','));

  return [headers.join(','), ...rows].join('\n');
}

export function downloadCSV(content: string, filename: string) {
  const blob = new Blob([content], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", filename);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
}

