function ProgressPage({ profiles, onComplete }: { profiles: Profile[], onComplete: (enriched: Profile[]) => void }) {
  const [progress, setProgress] = useState<EnrichmentProgress>({
    current: 0,
    total: profiles.length,
    percentage: '0',
    currentName: '',
    logs: []
  });
  const processedRef = useRef<Profile[]>([]);
  const isEnriching = useRef(false);

  useEffect(() => {
    if (isEnriching.current) return;
    isEnriching.current = true;

    const startEnrichment = async () => {
      const enriched: Profile[] = [];

      for (let i = 0; i < profiles.length; i++) {
        const p = profiles[i];
        setProgress(prev => ({
          ...prev,
          current: i + 1,
          currentName: p.name,
          percentage: (((i + 1) / profiles.length) * 100).toFixed(1)
        }));

        try {
          const result = await enrichWithGemini(p.name, p.title, p.company);

          let enrichedProfile: Profile;
          if (result.is_valid) {
            enrichedProfile = {
              ...p,
              ...result,
              enrichment_status: 'success',
              enrichment_source: 'gemini_web'
            };
          } else {
            const fallback = await inferFromTitle(p.title, p.company);
            enrichedProfile = {
              ...p,
              background: `Professional at ${p.company}.`,
              what_they_do: fallback.typical_responsibilities,
              skills: fallback.typical_skills,
              enrichment_status: 'fallback',
              enrichment_source: 'title_inference'
            };
          }

          // Generate embedding for search
          const searchText = `${enrichedProfile.name} ${enrichedProfile.title} ${enrichedProfile.company} ${enrichedProfile.background} ${enrichedProfile.what_they_do} ${(enrichedProfile.skills || []).join(' ')}`;
          enrichedProfile.embedding = await getProfileEmbedding(searchText);

          enriched.push(enrichedProfile);
          setProgress(prev => ({
            ...prev,
            logs: [{ name: p.name, status: result.is_valid ? 'success' : 'fallback', message: result.is_valid ? 'Found professional profile' : 'Inferred from title' }, ...prev.logs].slice(0, 50)
          }));
        } catch (error) {
          console.error(`Error enriching ${p.name}:`, error);
          enriched.push({ ...p, enrichment_status: 'error' });
          setProgress(prev => ({
            ...prev,
            logs: [{ name: p.name, status: 'error', message: 'Failed to enrich profile' }, ...prev.logs].slice(0, 50)
          }));
        }

        // Delay to respect rate limits
        await sleep(2500);
      }

      processedRef.current = enriched;
      onComplete(enriched);
    };

    startEnrichment();
  }, [profiles, onComplete]);

  return (
    <div className="max-w-4xl mx-auto py-12 px-4">
      <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100">
        <div className="p-8 border-b border-slate-50 bg-slate-50/50">
          <div className="flex justify-between items-end mb-6">
            <div>
              <h2 className="text-3xl font-black text-slate-900">Enriching Intelligence</h2>
              <p className="text-slate-500">Processing attendee profiles with Gemini Pro</p>
            </div>
            <div className="text-right">
              <span className="text-4xl font-black text-blue-600">{progress.percentage}%</span>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Complete</p>
            </div>
          </div>

          <div className="w-full bg-slate-200 rounded-full h-4 overflow-hidden shadow-inner">
            <div 
              className="bg-blue-600 h-full transition-all duration-500 ease-out"
              style={{ width: `${progress.percentage}%` }}
            ></div>
          </div>
          <p className="mt-4 text-sm text-slate-600 font-medium">
            Currently analyzing: <span className="text-blue-600">{progress.currentName || 'Starting...'}</span>
          </p>
        </div>

        <div className="p-8">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Activity Stream</h3>
          <div className="space-y-3 h-[400px] overflow-y-auto pr-4 scroll-smooth">
            {progress.logs.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-slate-400 italic">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mb-4"></div>
                Initializing AI engine...
              </div>
            )}
            {progress.logs.map((log, i) => (
              <div key={i} className="flex items-center gap-4 bg-slate-50 p-4 rounded-xl border border-slate-100 animate-fadeIn">
                <span className="text-xl">
                  {log.status === 'success' ? '✅' : log.status === 'fallback' ? '📝' : '❌'}
                </span>
                <div className="flex-1">
                  <p className="text-sm font-bold text-slate-800">{log.name}</p>
                  <p className="text-xs text-slate-500">{log.message}</p>
                </div>
                <span className={`text-[10px] font-black uppercase px-2 py-1 rounded ${
                  log.status === 'success' ? 'text-green-600 bg-green-50' :
                  log.status === 'fallback' ? 'text-orange-600 bg-orange-50' :
                  'text-red-600 bg-red-50'
                }`}>
                  {log.status}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function ResultsPage({ profiles }: { profiles: Profile[] }) {
  const [searchQuery, setSearchQuery] = useState('');
  const [results, setResults] = useState<Profile[]>(profiles);
  const [isSearching, setIsSearching] = useState(false);

  const handleSearch = async () => {
    if (!searchQuery.trim()) {
      setResults(profiles);
      return;
    }

    setIsSearching(true);
    try {
      const queryEmbedding = await getProfileEmbedding(searchQuery);
      const ranked = profiles.map(p => ({
        ...p,
        score: p.embedding ? cosineSimilarity(queryEmbedding, p.embedding) : 0
      })).sort((a, b) => (b.score || 0) - (a.score || 0));

      setResults(ranked);
    } catch (error) {
      console.error("Search failed:", error);
      // Fallback to simple text search
      const filtered = profiles.filter(p => 
        p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        p.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        p.background?.toLowerCase().includes(searchQuery.toLowerCase())
      );
      setResults(filtered);
    } finally {
      setIsSearching(false);
    }
  };

  const onExport = () => {
    const csvContent = exportToCSV(profiles);
    downloadCSV(csvContent, 'enriched_attendees.csv');
  };

  return (
    <div className="max-w-6xl mx-auto py-12 px-4">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-12">
        <div>
          <h2 className="text-4xl font-black text-slate-900">Networking Intelligence</h2>
          <p className="text-slate-500">Discover key people and deep insights from your event list.</p>
        </div>
        <button 
          onClick={onExport}
          className="bg-slate-900 text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 hover:bg-slate-800 transition-colors shadow-lg"
        >
          <span>📤</span> Export Enriched CSV
        </button>
      </div>

      <div className="relative mb-12">
        <input 
          type="text"
          placeholder="Semantic Search (e.g., 'experts in healthcare biotech' or 'SaaS founders')"
          className="w-full bg-white border-2 border-slate-200 rounded-3xl px-8 py-6 text-lg shadow-sm focus:border-blue-500 focus:outline-none transition-all pr-32"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
        />
        <button 
          onClick={handleSearch}
          disabled={isSearching}
          className="absolute right-4 top-4 bottom-4 bg-blue-600 text-white px-6 rounded-2xl font-bold hover:bg-blue-700 transition-colors disabled:opacity-50"
        >
          {isSearching ? '...' : 'Search'}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {results.map((profile) => (
          <ProfileCard key={profile.id} profile={profile} />
        ))}
        {results.length === 0 && (
          <div className="col-span-full py-20 text-center text-slate-400 italic">
            No profiles found matching your query.
          </div>
        )}
      </div>
    </div>
  );
}

