                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function ResultsPage({ profiles }: { profiles: Profile[] }) {
  const [searchQuery, setSearchQuery] = useState('');
  const [results, setResults] = useState<Profile[]>(profiles);

  const handleSearch = () => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) {
      setResults(profiles);
      return;
    }

    const filtered = profiles.map(p => {
      let score = 0;
      const content = `${p.name} ${p.title} ${p.company} ${p.background} ${p.what_they_do} ${(p.skills || []).join(' ')}`.toLowerCase();

      // Simple text match scoring
      if (content.includes(query)) score += 0.5;
      query.split(' ').forEach(word => {
        if (word.length > 2 && content.includes(word)) score += 0.1;
      });

      return { ...p, score };
    })
    .filter(p => (p.score || 0) > 0)
    .sort((a, b) => (b.score || 0) - (a.score || 0));

    setResults(filtered);
  };

  const onExport = () => {
    const csvContent = exportToCSV(profiles);
    downloadCSV(csvContent, 'enriched_attendees.csv');
  };

  return (
    <div className="max-w-6xl mx-auto py-12 px-4">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-12">
        <div>
