// Utility for sleep/rate-limiting
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

function UploadPage({ onUpload }: { onUpload: (profiles: Profile[]) => void }) {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      const parsed = parseCSV(text);
      onUpload(parsed as Profile[]);
    };
    reader.readAsText(file);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFile(e.dataTransfer.files[0]);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] px-4 animate-fadeIn">
      <div className="text-center mb-12">
        <h1 className="text-5xl md:text-6xl font-black text-slate-50 mb-4 tracking-tighter">
          TechWalk <span className="text-blue-500 drop-shadow-[0_0_15px_rgba(59,130,246,0.3)]">Connect</span>
        </h1>
        <p className="text-xl text-slate-400 max-w-lg mx-auto font-light">
          Elevate your networking data with AI-driven professional insights.
        </p>
      </div>

      <div 
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={onDrop}
        onClick={() => fileInputRef.current?.click()}
        className={`w-full max-w-2xl p-16 border-2 border-dashed rounded-[2.5rem] cursor-pointer transition-all duration-500 flex flex-col items-center gap-6 group ${
          isDragging ? 'border-blue-500 bg-blue-500/5 scale-[1.02]' : 'border-slate-800 bg-slate-900/30 hover:border-slate-600 hover:bg-slate-900/50'
        }`}
      >
        <div className="w-24 h-24 bg-blue-600 rounded-3xl flex items-center justify-center text-white text-5xl shadow-[0_0_30px_rgba(37,99,235,0.4)] group-hover:scale-110 transition-transform">
