export function parseCSV(text: string): Partial<Profile>[] {
  const lines = text.split(/\r?\n/).filter(line => line.trim().length > 0);
  if (lines.length < 2) return [];

  // Simple CSV parser that handles basic quoting
  const splitLine = (line: string) => {
    const result = [];
    let cur = "";
    let inQuote = false;
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        inQuote = !inQuote;
      } else if (char === ',' && !inQuote) {
        result.push(cur.trim().replace(/^"(.*)"$/, '$1'));
        cur = "";
      } else {
        cur += char;
      }
    }
    result.push(cur.trim().replace(/^"(.*)"$/, '$1'));
    return result;
  };

  const headers = splitLine(lines[0]).map(h => h.toLowerCase());

  const nameIdx = headers.findIndex(h => h.includes('name'));
  const titleIdx = headers.findIndex(h => ['title', 'role', 'position'].some(k => h.includes(k)));
  const companyIdx = headers.findIndex(h => ['company', 'org', 'employer'].some(k => h.includes(k)));
  const linkedinIdx = headers.findIndex(h => ['linkedin', 'url', 'link'].some(k => h.includes(k)));
  const emailIdx = headers.findIndex(h => h.includes('email'));

  return lines.slice(1).map((line, i) => {
    const values = splitLine(line);
    return {
      id: `profile-${i}-${Date.now()}`,
      name: values[nameIdx] || 'Unknown',
      title: values[titleIdx] || 'N/A',
      company: values[companyIdx] || 'N/A',
      linkedin_url: linkedinIdx !== -1 ? values[linkedinIdx] : undefined,
      email: emailIdx !== -1 ? values[emailIdx] : undefined,
      enrichment_status: 'pending',
