/**
 * Strips event-platform garbage text from strings.
 * Example: "[https://luma.com/...] has registered for TechWalk | Bangalore]" -> ""
 */
function cleanValue(val: string): string {
  if (!val) return '';

  return val
    // Remove content inside square brackets [...] including the brackets
    .replace(/\[.*?\]/g, '')
    // Remove registration boilerplate phrases and anything after them
    .replace(/has registered for.*/gi, '')
    // Remove trailing pipes or location markers often found in Luma exports
    .replace(/\|.*/g, '')
    // Remove extra whitespace and newlines
    .replace(/\s+/g, ' ')
    .trim();
}

/**
 * Specifically cleans LinkedIn/URL fields to extract just the link.
 */
function extractUrl(val: string): string | undefined {
  if (!val) return undefined;

  // Try to find a URL inside brackets if the whole string is messy
  const bracketMatch = val.match(/\[(https?:\/\/[^\]]+)\]/);
  if (bracketMatch && bracketMatch[1]) {
    const url = bracketMatch[1];
    // If it's a luma link and not linkedin, we might want to ignore it
    if (url.includes('linkedin.com')) return url;
  }

  // Clean basic text and check if it's a URL
  const cleaned = val.trim().replace(/^["']|["']$/g, '');
  if (cleaned.startsWith('http') || cleaned.includes('linkedin.com/')) {
    return cleaned;
  }

  return undefined;
}

export function parseCSV(text: string): Partial<Profile>[] {
  const lines = text.split(/\r?\n/).filter(line => line.trim().length > 0);
  if (lines.length < 2) return [];

  // Robust CSV parser that handles quotes and commas
  const splitLine = (line: string) => {
    const result = [];
    let cur = "";
    let inQuote = false;
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        inQuote = !inQuote;
      } else if (char === ',' && !inQuote) {
        result.push(cur.trim());
        cur = "";
      } else {
        cur += char;
      }
    }
    result.push(cur.trim());
    return result;
  };

  const headers = splitLine(lines[0]).map(h => h.toLowerCase().replace(/^["']|["']$/g, ''));

  // Find indices for common column names
  const nameIdx = headers.findIndex(h => h.includes('name'));
  const titleIdx = headers.findIndex(h => ['title', 'role', 'position', 'job'].some(k => h.includes(k)));
  const companyIdx = headers.findIndex(h => ['company', 'org', 'employer', 'work'].some(k => h.includes(k)));
  const linkedinIdx = headers.findIndex(h => ['linkedin', 'url', 'link', 'social'].some(k => h.includes(k)));
  const emailIdx = headers.findIndex(h => h.includes('email'));

  return lines.slice(1).map((line, i) => {
    const values = splitLine(line).map(v => v.replace(/^["']|["']$/g, ''));

    const rawName = nameIdx !== -1 ? values[nameIdx] : 'Unknown';
    const rawTitle = titleIdx !== -1 ? values[titleIdx] : 'N/A';
    const rawCompany = companyIdx !== -1 ? values[companyIdx] : 'N/A';
    const rawLinkedIn = linkedinIdx !== -1 ? values[linkedinIdx] : undefined;

    return {
      id: `profile-${i}-${Date.now()}`,
      name: cleanValue(rawName) || 'Unknown Attendee',
      title: cleanValue(rawTitle) || 'Professional',
