function ProgressPage({ profiles, onComplete }: { profiles: Profile[], onComplete: (enriched: Profile[]) => void }) {
  const [progress, setProgress] = useState<EnrichmentProgress>({
    current: 0,
    total: profiles.length,
    percentage: '0',
    currentName: '',
    logs: []
  });
  const processedRef = useRef<Profile[]>([]);
  const isEnriching = useRef(false);

  useEffect(() => {
    if (isEnriching.current) return;
    isEnriching.current = true;

    const startEnrichment = async () => {
      const enriched: Profile[] = [];

      for (let i = 0; i < profiles.length; i++) {
        const p = profiles[i];
        setProgress(prev => ({
          ...prev,
          current: i + 1,
          currentName: p.name,
          percentage: (((i + 1) / profiles.length) * 100).toFixed(1)
        }));

        try {
          const result = await enrichWithGemini(p.name, p.title, p.company, p.linkedin_url);

          let enrichedProfile: Profile;
          if (result.is_valid) {
            enrichedProfile = {
              ...p,
              ...result,
              enrichment_status: 'success',
              enrichment_source: 'gemini_web'
            };
          } else {
            const fallback = await inferFromTitle(p.title, p.company);
            enrichedProfile = {
              ...p,
              background: p.title ? `Professional at ${p.company || 'Industry'}.` : `Attendee at TechWalk.`,
              what_they_do: fallback.typical_responsibilities,
              skills: fallback.typical_skills,
              enrichment_status: 'fallback',
              enrichment_source: 'title_inference'
            };
          }

          enriched.push(enrichedProfile);
          const status: 'success' | 'fallback' = result.is_valid ? 'success' : 'fallback';
          setProgress(prev => ({
            ...prev,
            logs: [{ 
              name: p.name, 
              status: status, 
              message: result.is_valid ? 'Profile enriched successfully' : 'Using general inference' 
            }, ...prev.logs].slice(0, 50)
          }));
        } catch (error) {
          console.error(`Error enriching ${p.name}:`, error);
          enriched.push({ ...p, enrichment_status: 'error', enrichment_source: 'none' });
          setProgress(prev => ({
            ...prev,
            logs: [{ name: p.name, status: 'error' as const, message: 'API connection failed' }, ...prev.logs].slice(0, 50)
          }));
        }

        await sleep(1500);
      }

      processedRef.current = enriched;
      onComplete(enriched);
    };

    startEnrichment();
  }, [profiles, onComplete]);

  return (
    <div className="max-w-4xl mx-auto py-12 px-4 animate-fadeIn">
      <div className="bg-slate-900/60 backdrop-blur-xl rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-800">
        <div className="p-10 border-b border-slate-800/50 bg-slate-900/40">
          <div className="flex justify-between items-end mb-8">
            <div>
              <h2 className="text-3xl font-black text-slate-50 tracking-tight">AI Analysis in Progress</h2>
              <p className="text-slate-400 font-light mt-1 text-sm uppercase tracking-widest">Powered by Gemini Intelligence</p>
            </div>
            <div className="text-right">
              <span className="text-5xl font-black text-blue-500 drop-shadow-[0_0_10px_rgba(59,130,246,0.3)]">{progress.percentage}%</span>
            </div>
          </div>

          <div className="w-full bg-slate-800/80 rounded-full h-5 overflow-hidden shadow-inner border border-slate-700/50">
            <div 
              className="bg-gradient-to-r from-blue-600 via-blue-500 to-cyan-400 h-full transition-all duration-700 ease-out shadow-[0_0_20px_rgba(59,130,246,0.5)]"
              style={{ width: `${progress.percentage}%` }}
            ></div>
          </div>
          <div className="mt-6 flex items-center gap-3">
             <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></div>
             <p className="text-sm text-slate-300 font-light tracking-wide">
                Enriching: <span className="text-blue-400 font-bold">{progress.currentName || 'Ready...'}</span>
             </p>
          </div>
        </div>

        <div className="p-10">
          <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.3em] mb-6">Enrichment Stream</h3>
          <div className="space-y-4 h-[350px] overflow-y-auto pr-4 custom-scrollbar">
            {progress.logs.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-slate-600 italic">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-blue-500 mb-6 shadow-[0_0_15px_rgba(59,130,246,0.2)]"></div>
                Warmup up AI nodes...
              </div>
            )}
            {progress.logs.map((log, i) => (
              <div key={i} className="flex items-center gap-5 bg-slate-950/40 p-5 rounded-2xl border border-slate-800/60 hover:border-slate-700 transition-colors group">
                <div className={`w-3 h-3 rounded-full ${
                  log.status === 'success' ? 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]' : 
                  log.status === 'fallback' ? 'bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)]' : 
                  'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.5)]'
                }`}></div>
                <div className="flex-1">
                  <p className="text-sm font-bold text-slate-100 tracking-tight">{log.name}</p>
                  <p className="text-xs text-slate-500 font-light mt-0.5">{log.message}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

