import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { EnrichmentResult, FallbackResult, GroundingLink } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Identifies basic role/company for a profile missing info.
 */
export async function identifyRole(name: string, linkedinUrl?: string): Promise<{ title: string; company: string }> {
  const prompt = `
    Identify the current professional role and company for this person.
    Name: ${name}
    ${linkedinUrl ? `LinkedIn: ${linkedinUrl}` : ''}

    Return JSON:
    { "title": "Current Job Title", "company": "Current Company" }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            company: { type: Type.STRING }
          },
          required: ["title", "company"]
        }
      }
    });
    return JSON.parse(response.text.trim());
  } catch (error) {
    console.error("Role Identification Error:", error);
    return { title: '', company: '' };
  }
}

/**
 * Deep extraction of profile info.
 */
export async function enrichWithGemini(
  name: string,
  title: string,
  company: string,
  linkedinUrl?: string
): Promise<EnrichmentResult> {
  const prompt = `
    Perform a deep professional analysis of this person.
    Name: ${name}
    Role: ${title} at ${company}
    ${linkedinUrl ? `LinkedIn: ${linkedinUrl}` : ''}

    Extract and return a JSON object with:
    1. "background": 2-3 sentence summary of professional history.
    2. "what_they_do": 1-2 sentences on current responsibilities.
    3. "achievements": Notable awards or recognition.
    4. "skills": Array of 5-15 skills.
    5. "is_valid": boolean (true if info is found).

    Return ONLY JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            background: { type: Type.STRING },
            what_they_do: { type: Type.STRING },
            achievements: { type: Type.STRING },
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            is_valid: { type: Type.BOOLEAN }
          },
          required: ["background", "what_they_do", "achievements", "skills", "is_valid"]
        }
      },
    });

    const result = JSON.parse(response.text.trim());
    const groundingUrls: GroundingLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web && chunk.web.uri) {
          groundingUrls.push({ uri: chunk.web.uri, title: chunk.web.title || "Source" });
        }
      });
    }

    return { ...result, grounding_urls: groundingUrls } as EnrichmentResult;
  } catch (error) {
    console.error(`Gemini Enrichment Error for ${name}:`, error);
    throw error;
  }
}

export async function inferFromTitle(title: string, company: string): Promise<FallbackResult> {
  if (!title && !company) {
    return { typical_responsibilities: "Information unavailable.", typical_skills: ["Professional"] };
  }
  const prompt = `Provide typical responsibilities and skills for: ${title} at ${company}`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            typical_responsibilities: { type: Type.STRING },
            typical_skills: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["typical_responsibilities", "typical_skills"]
        }
      }
    });
    return JSON.parse(response.text.trim()) as FallbackResult;
  } catch (error) {
    return { typical_responsibilities: "N/A", typical_skills: [] };
  }
}

