          <p className="text-2xl font-bold text-slate-100">Upload CSV</p>
          <p className="text-slate-500 mt-2 font-light">Drag & drop or click to select file</p>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept=".csv" onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0])} />
      </div>
    </div>
  );
}

