import { Profile } from "../types";

/**
 * Strips event-platform garbage text and handles "no-data" placeholders.
 * Now handles Luma-style multi-line email bodies in fields.
 */
function cleanValue(val: string): string {
  if (!val) return '';

  // Extract only the first line - Luma often puts the whole email body in the Name field
  const firstLine = val.split(/\r?\n/)[0].trim();

  const cleaned = firstLine
    // Remove content inside square brackets [...]
    .replace(/\[.*?\]/g, '')
    // Remove registration boilerplate phrases
    .replace(/has registered for.*/gi, '')
    // Remove trailing pipes/locations
    .replace(/\|.*/g, '')
    // Remove extra whitespace
    .replace(/\s+/g, ' ')
    .trim();

  // Check for common "N/A" placeholders
  const lower = cleaned.toLowerCase();
  const placeholders = ['n/a', 'na', 'n.a.', 'none', 'not applicable', 'unknown', 'null', '0', '.'];
  if (placeholders.includes(lower) || !cleaned) {
    return '';
  }

  return cleaned;
}

/**
 * Specifically cleans LinkedIn/URL fields to extract just the link.
 */
function extractUrl(val: string): string | undefined {
  if (!val) return undefined;

  // Try to find a URL inside brackets
  const bracketMatch = val.match(/\[(https?:\/\/[^\]]+)\]/);
  let url = bracketMatch ? bracketMatch[1] : val.trim().replace(/^["']|["']$/g, '');

  // Reject common "not applicable" stubs
  if (url.toLowerCase().includes('notapplicable') || url.toLowerCase().includes('placeholder')) {
    return undefined;
  }

  // Ensure it's a valid http link
  if (url.startsWith('http') || url.includes('linkedin.com/')) {
    if (!url.startsWith('http')) url = `https://${url}`;
    return url;
  }

  return undefined;
}

export function parseCSV(text: string): Partial<Profile>[] {
  const lines = text.split(/\r?\n/).filter(line => line.trim().length > 0);
  if (lines.length < 2) return [];

  const splitLine = (line: string) => {
    const result = [];
    let cur = "";
    let inQuote = false;
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        inQuote = !inQuote;
      } else if (char === ',' && !inQuote) {
        result.push(cur.trim());
        cur = "";
      } else {
        cur += char;
      }
    }
    result.push(cur.trim());
    return result;
  };

  const headers = splitLine(lines[0]).map(h => h.toLowerCase().replace(/^["']|["']$/g, ''));

  const nameIdx = headers.findIndex(h => h.includes('name'));
  const titleIdx = headers.findIndex(h => ['title', 'role', 'position', 'job'].some(k => h.includes(k)));
  const companyIdx = headers.findIndex(h => ['company', 'org', 'employer', 'work'].some(k => h.includes(k)));
  const linkedinIdx = headers.findIndex(h => ['profile', 'linkedin', 'url', 'link', 'social'].some(k => h.includes(k)));
  const emailIdx = headers.findIndex(h => h.includes('email'));

  return lines.slice(1).map((line, i) => {
    const values = splitLine(line).map(v => v.replace(/^["']|["']$/g, ''));

    const rawName = nameIdx !== -1 ? values[nameIdx] : 'Unknown';
    const rawTitle = titleIdx !== -1 ? values[titleIdx] : '';
    const rawCompany = companyIdx !== -1 ? values[companyIdx] : '';
    const rawLinkedIn = linkedinIdx !== -1 ? values[linkedinIdx] : undefined;

    return {
      id: `profile-${i}-${Date.now()}`,
      name: cleanValue(rawName) || 'Unknown Attendee',
      title: cleanValue(rawTitle),
      company: cleanValue(rawCompany),
      linkedin_url: extractUrl(rawLinkedIn),
      email: emailIdx !== -1 ? values[emailIdx] : undefined,
      enrichment_status: 'pending',
      enrichment_source: 'none'
    };
  });
}

export function exportToCSV(profiles: Profile[]): string {
  const headers = ['Name', 'Title', 'Company', 'LinkedIn', 'Background', 'Responsibilities', 'Achievements', 'Skills'];
  const rows = profiles.map(p => [
    `"${p.name}"`,
    `"${p.title || ''}"`,
    `"${p.company || ''}"`,
    `"${p.linkedin_url || ''}"`,
    `"${(p.background || '').replace(/"/g, '""')}"`,
    `"${(p.what_they_do || '').replace(/"/g, '""')}"`,
    `"${(p.achievements || '').replace(/"/g, '""')}"`,
    `"${(p.skills || []).join(', ')}"`
  ].join(','));

  return [headers.join(','), ...rows].join('\n');
}

export function downloadCSV(content: string, filename: string) {
  const blob = new Blob([content], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", filename);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
}

