const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

function UploadPage({ onRawLoad }: { onRawLoad: (headers: string[], rows: string[][]) => void }) {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      const { headers, rows } = parseRawCSV(text);
      onRawLoad(headers, rows);
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] px-4 animate-fadeIn">
      <div className="text-center mb-12">
        <h1 className="text-5xl md:text-6xl font-black text-slate-50 mb-4 tracking-tighter">
          TechWalk <span className="text-blue-500 drop-shadow-[0_0_15px_rgba(59,130,246,0.3)]">Connect</span>
        </h1>
        <p className="text-xl text-slate-400 max-w-lg mx-auto font-light italic">
          High-fidelity networking intelligence.
        </p>
      </div>
      <div 
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); if (e.dataTransfer.files?.[0]) handleFile(e.dataTransfer.files[0]); }}
        onClick={() => fileInputRef.current?.click()}
        className={`w-full max-w-2xl p-16 border-2 border-dashed rounded-[2.5rem] cursor-pointer transition-all duration-500 flex flex-col items-center gap-6 group ${
          isDragging ? 'border-blue-500 bg-blue-500/5 scale-[1.02]' : 'border-slate-800 bg-slate-900/30 hover:border-slate-600 hover:bg-slate-900/50'
        }`}
      >
        <div className="w-24 h-24 bg-blue-600 rounded-3xl flex items-center justify-center text-white text-5xl shadow-[0_0_30px_rgba(37,99,235,0.4)] group-hover:scale-110 transition-transform">📄</div>
        <div className="text-center">
          <p className="text-2xl font-bold text-slate-100">Upload CSV</p>
          <p className="text-slate-500 mt-2 font-light">Drag & drop or click to select file</p>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept=".csv" onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0])} />
      </div>
    </div>
  );
}

function MappingPage({ headers, rows, onComplete }: { headers: string[], rows: string[][], onComplete: (profiles: Profile[]) => void }) {
  const [mappings, setMappings] = useState<ColumnMapping[]>([]);

  useEffect(() => {
    setMappings(detectMappings(headers, rows));
  }, [headers, rows]);

  const updateMapping = (idx: number, field: FieldType) => {
    setMappings(prev => prev.map((m, i) => i === idx ? { ...m, mappedTo: field } : m));
  };

  const handleFinalize = () => {
    onComplete(finalizeProfiles(mappings, rows));
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-4 animate-fadeIn">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-3xl font-black text-slate-50 tracking-tight">Map Your Columns</h2>
