import { Profile, ColumnMapping, FieldType } from "../types";
import * as XLSX from "xlsx";

/**
 * Advanced CSV Parser that respects quoted multiline fields.
 */
export function parseRawCSV(text: string): { headers: string[], rows: string[][] } {
  const result: string[][] = [];
  let row: string[] = [];
  let currField = "";
  let inQuotes = false;

  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    const nextChar = text[i + 1];

    if (inQuotes) {
      if (char === '"' && nextChar === '"') {
        currField += '"';
        i++;
      } else if (char === '"') {
        inQuotes = false;
      } else {
        currField += char;
      }
    } else {
      if (char === '"') {
        inQuotes = true;
      } else if (char === ',') {
        row.push(currField.trim());
        currField = "";
      } else if (char === '\n' || (char === '\r' && nextChar === '\n')) {
        if (char === '\r') i++;
        row.push(currField.trim());
        result.push(row);
        row = [];
        currField = "";
      } else {
        currField += char;
      }
    }
  }

  if (row.length > 0 || currField) {
    row.push(currField.trim());
    result.push(row);
  }

  const headers = result[0] || [];
  const rows = result.slice(1);
  return { headers, rows };
}

export function detectMappings(headers: string[], rows: string[][]): ColumnMapping[] {
  return headers.map((header, idx) => {
    const h = header.toLowerCase();
    let mappedTo: FieldType = 'ignore';
    let autoDetected = true;

    if (h.includes('name')) mappedTo = 'name';
    else if (h.includes('title') || h.includes('role')) mappedTo = 'title';
    else if (h.includes('company') || h.includes('work')) mappedTo = 'company';
    else if (h.includes('linkedin') || h.includes('profile')) mappedTo = 'linkedin_url';
    else if (h.includes('email')) mappedTo = 'email';
    else autoDetected = false;

    const preview = rows.slice(0, 3).map(r => r[idx] || '').filter(v => v !== '');

    return { header, mappedTo, preview, autoDetected };
  });
}

function cleanLumaGarbage(val: string): string {
  if (!val) return '';
  // Extract first line and strip common Luma fragments
  const lines = val.split(/\r?\n/);
  let cleaned = lines[0]
    .replace(/\[.*?\]/g, '')
    .replace(/has registered for.*/gi, '')
    .replace(/registered for your event/gi, '')
    .replace(/\|.*/g, '')
    .trim();

  const placeholders = ['n/a', 'na', 'none', '.', '0', 'not applicable', '#n/a'];
  if (placeholders.includes(cleaned.toLowerCase())) return '';

  return cleaned;
}

export function finalizeProfiles(mappings: ColumnMapping[], rows: string[][]): Profile[] {
  return rows.map((row, rowIdx) => {
    const profile: any = {
      id: `profile-${rowIdx}-${Date.now()}`,
      enrichment_status: 'pending',
      enrichment_source: 'none',
      selected: true
    };

    mappings.forEach((m, colIdx) => {
      if (m.mappedTo !== 'ignore') {
        const val = row[colIdx];
        if (m.mappedTo === 'name') {
           profile.name = cleanLumaGarbage(val) || 'Unknown Attendee';
        } else if (m.mappedTo === 'linkedin_url') {
           const match = val?.match(/https?:\/\/[^\s\]]+/);
           profile.linkedin_url = match ? match[0] : undefined;
        } else {
           profile[m.mappedTo] = cleanLumaGarbage(val);
        }
      }
    });

    return profile as Profile;
  });
}

export function exportToCSV(profiles: Profile[]): string {
  const headers = ['Name', 'Title', 'Company', 'LinkedIn', 'Background', 'Current Focus', 'Skills'];
  const rows = profiles.map(p => [
    `"${p.name}"`,
    `"${p.title || ''}"`,
    `"${p.company || ''}"`,
    `"${p.linkedin_url || ''}"`,
    `"${(p.background || '').replace(/"/g, '""')}"`,
    `"${(p.what_they_do || '').replace(/"/g, '""')}"`,
    `"${(p.skills || []).join(', ')}"`
  ].join(','));
  return [headers.join(','), ...rows].join('\n');
}

export function exportToJSON(profiles: Profile[]): string {
  return JSON.stringify(profiles, null, 2);
}

export function downloadXLSX(profiles: Profile[], filename: string) {
  const data = profiles.map(p => ({
    Name: p.name,
    Title: p.title,
    Company: p.company,
    LinkedIn: p.linkedin_url,
    Background: p.background,
    CurrentFocus: p.what_they_do,
    Achievements: p.achievements,
    Skills: (p.skills || []).join(', '),
    Status: p.enrichment_status,
    Source: p.enrichment_source
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Enriched Profiles");
  XLSX.writeFile(workbook, filename);
}

export function downloadFile(content: string, filename: string, mimeType: string) {
  const blob = new Blob([content], { type: `${mimeType};charset=utf-8;` });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", filename);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
}

import React, { useState, useEffect, useRef } from 'react';
import { HashRouter as Router } from 'react-router-dom';
import { Profile, EnrichmentProgress, ColumnMapping, FieldType } from './types';
import { parseRawCSV, detectMappings, finalizeProfiles, exportToCSV, exportToJSON, downloadXLSX, downloadFile } from './services/csv';
import { enrichWithGemini, inferFromTitle, identifyRole } from './services/gemini';
import ProfileCard from './components/ProfileCard';

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

function UploadPage({ onRawLoad }: { onRawLoad: (headers: string[], rows: string[][]) => void }) {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      const { headers, rows } = parseRawCSV(text);
      onRawLoad(headers, rows);
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] px-4 animate-fadeIn">
      <div className="text-center mb-12">
        <h1 className="text-5xl md:text-6xl font-black text-slate-50 mb-4 tracking-tighter">
          LinkedIn <span className="text-blue-500 drop-shadow-[0_0_15px_rgba(59,130,246,0.3)]">Recommender</span>
        </h1>
        <p className="text-xl text-slate-400 max-w-lg mx-auto font-light italic">
          High-fidelity networking intelligence.
        </p>
      </div>
      <div 
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); if (e.dataTransfer.files?.[0]) handleFile(e.dataTransfer.files[0]); }}
        onClick={() => fileInputRef.current?.click()}
        className={`w-full max-w-2xl p-16 border-2 border-dashed rounded-[2.5rem] cursor-pointer transition-all duration-500 flex flex-col items-center gap-6 group ${
          isDragging ? 'border-blue-500 bg-blue-500/5 scale-[1.02]' : 'border-slate-800 bg-slate-900/30 hover:border-slate-600 hover:bg-slate-900/50'
        }`}
      >
        <div className="w-24 h-24 bg-blue-600 rounded-3xl flex items-center justify-center text-white text-5xl shadow-[0_0_30px_rgba(37,99,235,0.4)] group-hover:scale-110 transition-transform">📄</div>
        <div className="text-center">
          <p className="text-2xl font-bold text-slate-100">Upload CSV</p>
          <p className="text-slate-500 mt-2 font-light">Drag & drop or click to select file</p>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept=".csv" onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0])} />
      </div>
    </div>
  );
}

function MappingPage({ headers, rows, onComplete }: { headers: string[], rows: string[][], onComplete: (profiles: Profile[]) => void }) {
  const [mappings, setMappings] = useState<ColumnMapping[]>([]);

  useEffect(() => {
    setMappings(detectMappings(headers, rows));
  }, [headers, rows]);

  const updateMapping = (idx: number, field: FieldType) => {
    setMappings(prev => prev.map((m, i) => i === idx ? { ...m, mappedTo: field } : m));
  };

  const handleFinalize = () => {
    onComplete(finalizeProfiles(mappings, rows));
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-4 animate-fadeIn">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-3xl font-black text-slate-50 tracking-tight">Map Your Columns</h2>
          <p className="text-slate-400 font-light mt-1">We found {headers.length} columns and {rows.length} profiles</p>
        </div>
